module RefModule (
    input [3:0] current,
    output reg exceeds_threshold
);
  wire [3:0] _tap_current = current & {4{1'b1}};

    always @(*) begin
        if (current > 4'b1000) // 8 in binary
            exceeds_threshold = 1;
        else
            exceeds_threshold = 0;
    end
endmodule
